mapper.insert:
/* SapItemsExpiartionDateByShiptoPartyMapper.xml insertBatchTable 전송대상keep */ INSERT INTO TWORK_BATCH_STORE_IC_EXPIRE ( BASEDT /*기준일자 */ ,OWKEY /*화주 코드*/ ,STORE_KEY /*배송처코드*/ ,ICKEY /*상품코드*/ ,EXPIREDATE /*유통기한*/ ,PROCESSYN /*처리여부*/ ,BAT_EXEC_ID /*배치실행 ID*/ ,INSERTDATE ,INSERTURKEY ,UPDATEDATE ,UPDATEURKEY ) SELECT A.OUTBOUNDDT ,A.OWKEY ,A.STORE_KEY ,A.ICKEY ,MAX(SUBSTR(A.EXPIREDATE ,1, 8)) ,'N' ,#{batExecId} ,#{interfaceDate} ,#{btchNm} ,#{interfaceDate} ,#{btchNm} FROM TWORK_INFO_STORE_IC_EXPIRE A LEFT JOIN TWORK_BATCH_STORE_IC_EXPIRE B ON A.OUTBOUNDDT = B.BASEDT AND A.OWKEY = B.OWKEY AND A.STORE_KEY = B.STORE_KEY AND A.ICKEY = B.ICKEY AND B.PROCESSYN = 'N' WHERE A.OUTBOUNDDT = #{baseDt} AND A.OWKEY = #{owkey} AND B.BATCHKEY IS NULL
AND A.CTKEY = #{ctkey}
GROUP BY A.OWKEY,A.STORE_KEY ,A.ICKEY , A.OUTBOUNDDT
